mapper.select:
select YYYYMM, SEL_CODE, SITE AS SITE_ORG, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' end as SITE, MAT_CODE, MAT_DESC, [SIZE], IN_QTY, UNIT_COST, IN_AMT, COST_GUBUN, MAT_GUBUN, MAT_CLASS, MODEL, MODEL_N_TYPE from DOI_MATERIAL_RESC where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
order BY MAT_CODE, MODEL, MODEL_N_TYPE;

DROP TABLE IF EXISTS #TempTable1;

CREATE TABLE #TempTable1 (
	YYYYMM varchar(6) COLLATE Korean_Wansung_CI_AS NULL,
	SEL_CODE varchar(6) COLLATE Korean_Wansung_CI_AS NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_CODE varchar(24) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_DESC nvarchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	[SIZE] varchar(40) COLLATE Korean_Wansung_CI_AS NULL,
	IN_QTY real NULL,
	UNIT_COST real NULL,
	IN_AMT numeric(15,2) NULL,
	COST_GUBUN nvarchar(15) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_GUBUN nvarchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_CLASS nvarchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	MODEL varchar(15) COLLATE Korean_Wansung_CI_AS NULL,
	MODEL_N_TYPE varchar(15) COLLATE Korean_Wansung_CI_AS NULL
);

INSERT INTO #TempTable1
(
YYYYMM,SEL_CODE,SITE,MAT_CODE,MAT_DESC,[SIZE],IN_QTY,UNIT_COST,IN_AMT,COST_GUBUN,MAT_GUBUN,MAT_CLASS,MODEL,MODEL_N_TYPE
)
VALUES

	(
	#{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field5}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	, #{item.field9}
	, #{item.field10}
	, #{item.field11}
	, #{item.field12}
	, #{item.field13}
	, #{item.field14}
	, #{item.field15}
	)
;

SELECT * FROM #TempTable1 a
WHERE EXISTS (
	SELECT 1
	FROM DOI_MATERIAL_RESC b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SEL_CODE = a.SEL_CODE
	AND b.SITE = a.SITE
	AND b.MAT_CODE = a.MAT_CODE
	AND b.MODEL = a.MODEL
	AND b.MODEL_N_TYPE = a.MODEL_N_TYPE
);

mapper.insert:
CREATE TABLE #TempTable (
	seq_no INT IDENTITY (1, 1) NOT NULL,
	YYYYMM varchar(6) COLLATE Korean_Wansung_CI_AS NULL,
	SEL_CODE varchar(6) COLLATE Korean_Wansung_CI_AS NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_CODE varchar(24) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_DESC nvarchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	[SIZE] varchar(40) COLLATE Korean_Wansung_CI_AS NULL,
	IN_QTY real NULL,
	UNIT_COST real NULL,
	IN_AMT numeric(15,2) NULL,
	COST_GUBUN nvarchar(15) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_GUBUN nvarchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	MAT_CLASS nvarchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	MODEL varchar(15) COLLATE Korean_Wansung_CI_AS NULL,
	MODEL_N_TYPE varchar(15) COLLATE Korean_Wansung_CI_AS NULL
);

INSERT INTO #TempTable
(
YYYYMM,SEL_CODE,SITE,MAT_CODE,MAT_DESC,[SIZE],IN_QTY,UNIT_COST,IN_AMT,COST_GUBUN,MAT_GUBUN,MAT_CLASS,MODEL,MODEL_N_TYPE
)
VALUES

	(
	 #{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field5}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	, #{item.field9}
	, #{item.field10}
	, #{item.field11}
	, #{item.field12}
	, #{item.field13}
	, #{item.field14}
