INSERT INTO DOI_MATERIAL_RESC (YYYYMM,SEL_CODE,SITE,MAT_CODE,MAT_DESC,[SIZE],IN_QTY,UNIT_COST,IN_AMT,COST_GUBUN,MAT_GUBUN,MAT_CLASS,MODEL,MODEL_N_TYPE)
SELECT YYYYMM,SEL_CODE,SITE,MAT_CODE,MAT_DESC,[SIZE],IN_QTY,UNIT_COST,IN_AMT,COST_GUBUN,MAT_GUBUN,MAT_CLASS,MODEL,MODEL_N_TYPE
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYYMM, SEL_CODE, SITE, MAT_CODE, MODEL, MODEL_N_TYPE) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_MATERIAL_RESC b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SEL_CODE = a.SEL_CODE
	AND b.SITE = a.SITE
	AND b.MAT_CODE = a.MAT_CODE
	AND b.MODEL = a.MODEL
	AND b.MODEL_N_TYPE = a.MODEL_N_TYPE
);

DROP TABLE #TempTable;

INSERT INTO DOI_MATERIAL_RESC
(
YYYYMM,SEL_CODE,SITE,MAT_CODE,MAT_DESC,[SIZE],IN_QTY,UNIT_COST,IN_AMT,COST_GUBUN,MAT_GUBUN,MAT_CLASS,MODEL,MODEL_N_TYPE
)
VALUES
(
#{yyyymm}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='VINA' then 'VN' else left(#{site},2) end
, #{matCode}
, #{matDesc}
, #{size}
, #{inQty}
, #{unitCost}
, #{inAmt}
, #{costGubun}
, #{matGubun}
, #{matClass}
, #{model}
, #{modelNType}				
);

mapper.delete:
DELETE FROM DOI_MATERIAL_RESC
WHERE 1=1
and YYYYMM = #{yyyymm}
and SEL_CODE = #{selCode}
and SITE = #{siteOrg}
and MAT_CODE = #{matCode}
and MODEL = #{model}
and MODEL_N_TYPE = #{modelNType}

mapper.update:
