SET MAT_DESC = #{matDesc}
,[SIZE] = #{size}
,IN_QTY = #{inQty}
,UNIT_COST = #{unitCost}
,IN_AMT = #{inAmt}
,COST_GUBUN = #{costGubun}
,MAT_GUBUN = #{matGubun}
,MAT_CLASS = #{matClass}
WHERE 1=1
and YYYYMM = #{yyyymm}
and SEL_CODE = #{selCode}
and SITE = #{siteOrg}
and MAT_CODE = #{matCode}
and MODEL = #{model}
and MODEL_N_TYPE = #{modelNType}
;
